#include <stdio.h>
#include <signal.h>
#include <string.h>

volatile sig_atomic_t got_signal = 0;

void handler(int sig) {
    (void)sig;
    got_signal = 1;
}

int main(void) {
    signal(SIGUSR1, handler);

    /* Masquer SIGUSR1 */
    sigset_t block_set, old_set;
    sigemptyset(&block_set);
    sigaddset(&block_set, SIGUSR1);
    sigprocmask(SIG_BLOCK, &block_set, &old_set);
    printf("SIGUSR1 blocked\n");

    /* Envoyer le signal (il sera retenu) */
    raise(SIGUSR1);
    printf("After raise: got_signal=%d\n", got_signal);

    /* Verifier qu'il est en attente */
    sigset_t pending;
    sigpending(&pending);
    if (sigismember(&pending, SIGUSR1))
        printf("SIGUSR1 is pending\n");

    /* Demasquer */
    sigprocmask(SIG_UNBLOCK, &block_set, NULL);
    printf("After unblock: got_signal=%d\n", got_signal);

    return 0;
}

